import { Router } from "express";
import { createPayment, getPayments, getPaymentById, } from "./payment.controller.js";
import { authenticate } from "../../middlewares/auth.middleware.js";
import { requireRole } from "../../middlewares/rbac.middleware.js";
import { validateUuidParam } from "../../middlewares/uuid.middleware.js";
const router = Router();
router.param("id", validateUuidParam("id"));
router.use(authenticate);
router.post("/", requireRole("SUPER_ADMIN", "SALON_ADMIN", "RECEPTIONIST"), createPayment);
router.get("/", requireRole("SUPER_ADMIN", "SALON_ADMIN", "RECEPTIONIST"), getPayments);
router.get("/:id", requireRole("SUPER_ADMIN", "SALON_ADMIN", "RECEPTIONIST"), getPaymentById);
export default router;
